parameters.inputSchema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "type": "array",
  "items": {
    "type": "object",
    "required": ["SKU", "Descrição", "dataReferencia", "previsoes"],
    "properties": {
      "SKU": {
        "type": "integer",
        "description": "Código do produto"
      },
      "Descrição": {
        "type": "string",
        "description": "Descrição do produto"
      },
      "dataReferencia": {
        "type": "string",
        "format": "date",
        "description": "Data de referência no formato YYYY-MM-DD"
      },
      "previsoes": {
        "type": "array",
        "items": {
          "type": "object",
          "required": ["mes", "previsao", "intervaloConfianca", "confianca"],
          "properties": {
            "mes": {
              "type": "string",
              "pattern": "^[0-9]{4}-[0-9]{2}$",
              "description": "Mês no formato YYYY-MM"
            },
            "previsao": {
              "type": "number",
              "description": "Valor previsto"
            },
            "intervaloConfianca": {
              "type": "object",
              "required": ["lower", "upper"],
              "properties": {
                "lower": {
                  "type": "number",
                  "description": "Limite inferior do intervalo de confiança"
                },
                "upper": {
                  "type": "number",
                  "description": "Limite superior do intervalo de confiança"
                }
              },
              "additionalProperties": false
            },
            "confianca": {
              "type": "string",
              "enum": ["baixa", "média", "alta"],
              "description": "Nível de confiança da previsão"
            }
          },
          "additionalProperties": false
        }
      }
    },
    "additionalProperties": false
  }
}

